function fb(a, b) { if (a) { return a; } return b; }
const topic = fb($.input.topic, 'office life');
const style = fb($.input.style, 'short-form sketch');
const duration = fb($.input.duration, '60 seconds');

let prompt = 'You are a professional comedy writer who specializes in viral video scripts. Write a ' + style + ' comedy script about: ' + topic + '\n\n';
prompt += 'Target duration: ' + duration + '\n\n';
prompt += 'REQUIREMENTS:\n';
prompt += '- Include scene directions in [brackets]\n';
prompt += '- Write snappy dialogue with clear character labels\n';
prompt += '- Include timing notes for key beats\n';
prompt += '- End with a strong punchline or twist\n';
prompt += '- Keep it family-friendly but edgy enough to be shareable\n';
prompt += '- Include a suggested title and 3 hashtags\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "title": "catchy video title",\n';
prompt += '  "style": "script style",\n';
prompt += '  "duration": "estimated duration",\n';
prompt += '  "characters": ["Character A", "Character B"],\n';
prompt += '  "scenes": [\n';
prompt += '    { "sceneNumber": 1, "direction": "scene setup", "dialogue": [{ "character": "Name", "line": "dialogue line", "action": "optional action note" }], "timing": "0:00-0:15" }\n';
prompt += '  ],\n';
prompt += '  "punchline": "the final punchline or twist",\n';
prompt += '  "hashtags": ["#tag1", "#tag2", "#tag3"],\n';
prompt += '  "directorNotes": "brief production tips"\n';
prompt += '}';

return { prompt };

function fb(a, b) { if (a) { return a; } return b; }
let raw = fb($.steps.aiGenerate.output, '');
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: 'Comedy Script', scenes: [], text: raw }; }

function fb(a, b) { if (a) { return a; } return b; }
const ai = $.steps.parseResponse.output;
const topic = fb($.input.topic, 'comedy');

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':clapper: ' + (fb(ai.title, 'Comedy Script')), emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Style:* ' + (fb(fb(ai.style, $.input.style), 'sketch')) + '  |  *Duration:* ' + (fb(fb(ai.duration, $.input.duration), '60s')) + '  |  *Characters:* ' + (fb(ai.characters, [])).join(', ') } });
blocks.push({ type: 'divider' });

var scenes = fb(ai.scenes, []);
scenes.forEach(function(scene) {
  var sceneText = '*Scene ' + scene.sceneNumber + '* (' + (fb(scene.timing, '')) + ')\n';
  sceneText += '_[' + (fb(scene.direction, '')) + ']_\n';
  var dialogueList = fb(scene.dialogue, []);
  dialogueList.forEach(function(d) {
    sceneText += '*' + d.character + ':* ' + d.line;
    if (d.action) sceneText += ' _(' + d.action + ')_';
    sceneText += '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: sceneText } });
});

if (ai.punchline) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':tada: *Punchline:* ' + ai.punchline } });
}

if (ai.directorNotes) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':movie_camera: *Director Notes:* ' + ai.directorNotes }] });
}

var hashtagStr = (fb(ai.hashtags, [])).join(' ');
blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: hashtagStr + ' | Powered by Claude AI + One CLI' }] });

var fallback = 'Comedy Script: ' + (fb(ai.title, topic));
return { blocks: blocks, fallback: fallback };
